import './style.css'
import { PremblyPass } from 'prembly-pass'

// Get API key from environment variable
const apiKey = import.meta.env.VITE_PREMBLY_API_KEY || process.env.PREMBLY_API_KEY;

// Generate a unique user reference
const userRef = `user_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;

// Initialize PremblyPass with the required configuration
const premblyPass = new PremblyPass({
  app_id: 'test_app_id',
  x_api_key: apiKey,
  environment: 'test',
  api_url: 'https://api.prembly.com',
  config_id: 'test_config_id',
  user_ref: userRef
});

// Get DOM elements
const launchButton = document.getElementById('launch-widget');
const resultDiv = document.getElementById('result');

// Function to display result on the page
function displayResult(type, data) {
  resultDiv.innerHTML = `
    <div class="result-box ${type}">
      <h3>${type === 'success' ? '✅ Verification Successful' : '❌ Verification Failed'}</h3>
      <pre>${JSON.stringify(data, null, 2)}</pre>
    </div>
  `;
}

// Listen for success event
premblyPass.on('success', (data) => {
  console.log('Verification successful:', data);
  displayResult('success', data);
});

// Listen for error event
premblyPass.on('error', (error) => {
  console.error('Verification error:', error);
  displayResult('error', error);
});

// Add click handler to launch the widget
launchButton.addEventListener('click', () => {
  try {
    premblyPass.launch();
  } catch (error) {
    console.error('Error launching widget:', error);
    displayResult('error', { message: error.message });
  }
});

// Log initialization
console.log('PremblyPass initialized with user_ref:', userRef);

