.container {
  max-width: 800px;
  margin: 0 auto;
  padding: 60px 20px;
}

.launch-button {
  background: var(--accent);
  color: white;
  border: none;
  padding: 16px 32px;
  font-size: 18px;
  font-weight: 600;
  border-radius: 8px;
  cursor: pointer;
  transition: all 0.3s ease;
  box-shadow: var(--shadow);
  margin: 24px 0;

  &:hover {
    background: var(--accent-border);
    transform: translateY(-2px);
    box-shadow: 0 4px 12px rgba(170, 59, 255, 0.3);
  }

  &:active {
    transform: translateY(0);
  }

  &:focus-visible {
    outline: 3px solid var(--accent);
    outline-offset: 2px;
  }
}

