    overflow-x: auto;
    font-size: 14px;
    line-height: 1.5;
    margin: 0;
    color: var(--text-h);
  }
}

@keyframes fadeIn {
  from {
    opacity: 0;
    transform: translateY(10px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

